package main
import("encoding/json";"github.com/hyperledger/fabric-contract-api-go/contractapi")
type SceneContract struct{contractapi.Contract};func sceneKey(id string)string{return "scene:"+id};func avatarKey(id string)string{return "avatar:"+id};func sceneMemberKey(s,u string)string{return "scene_member:"+s+":"+u}
func(c *SceneContract)JoinScene(ctx contractapi.TransactionContextInterface,user_id,scene_id string)error{p:=map[string]any{"tx_type":"scene_join","contract":"scene","function":"JoinScene","args":map[string]string{"user_id":user_id,"scene_id":scene_id},"primary_key":sceneKey(scene_id),"access_keys":[]string{sceneKey(scene_id),avatarKey(user_id),sceneMemberKey(scene_id,user_id)},"event":"SceneJoined"};b,_:=json.Marshal(p);return ctx.GetStub().SetEvent("SceneJoined",b)}
func(c *SceneContract)CreateScene(ctx contractapi.TransactionContextInterface,id,name string,capacity int)error{return nil};func(c *SceneContract)CreateAvatar(ctx contractapi.TransactionContextInterface,id,status string)error{return nil};func(c *SceneContract)ReadScene(ctx contractapi.TransactionContextInterface,id string)(*Scene,error){return nil,nil};func(c *SceneContract)ReadAvatar(ctx contractapi.TransactionContextInterface,id string)(*Avatar,error){return nil,nil};func(c *SceneContract)InitLedger(ctx contractapi.TransactionContextInterface)error{return nil}
